import json
from dataclasses import dataclass, field
from pathlib import Path


@dataclass
class Config:
    """Runtime configuration loaded from a JSON file."""

    learning_rate: float = 3e-4
    batch_size: int = 32
    max_steps: int = 10_000
    tags: list[str] = field(default_factory=list)

    @classmethod
    def from_file(cls, path: str | Path) -> "Config":
        with open(path) as f:
            data = json.load(f)
        return cls(**data)

    def save(self, path: str | Path) -> None:
        Path(path).write_text(json.dumps(self.__dict__, indent=2))

def binary_search(arr: list[int], target: int) -> int:
    """Return the index of target in sorted arr, or -1 if absent."""
    lo, hi = 0, len(arr) - 1
    while lo <= hi:
        mid = (lo + hi) // 2
        if arr[mid] == target:
            return mid
        elif arr[mid] < target:
            lo = mid + 1
        else:
            hi = mid - 1
    return -1


if __name__ == "__main__":
    data = sorted([17, 3, 44, 8, 92, 61, 5])
    for needle in (8, 44, 100):
        print(f"{needle}: index {binary_search(data, needle)}")

import numpy as np


def softmax(x: np.ndarray, axis: int = -1) -> np.ndarray:
    shifted = x - x.max(axis=axis, keepdims=True)
    exp = np.exp(shifted)
    return exp / exp.sum(axis=axis, keepdims=True)


def cross_entropy(logits: np.ndarray, labels: np.ndarray) -> float:
    probs = softmax(logits)
    n = labels.shape[0]
    return float(-np.log(probs[np.arange(n), labels] + 1e-12).mean())


logits = np.random.randn(64, 10).astype(np.float32)
labels = np.random.randint(0, 10, size=64)
print(f"loss = {cross_entropy(logits, labels):.4f}")

