typedef struct Node {
    int value;
    struct Node *next;
} Node;

Node *push(Node *head, int value) {
    Node *node = malloc(sizeof(Node));
    if (node == NULL) {
        fprintf(stderr, "out of memory\n");
        exit(EXIT_FAILURE);
    }
    node->value = value;
    node->next = head;
    return node;
}

int main(void) {
    Node *head = NULL;
    for (int i = 0; i < 10; i++) {
        head = push(head, i * i);
    }
    for (Node *cur = head; cur != NULL; cur = cur->next) {
        printf("%d ", cur->value);
    }
    return 0;
}

async function fetchWithRetry(url, { retries = 3, backoffMs = 250 } = {}) {
  for (let attempt = 0; attempt <= retries; attempt++) {
    try {
      const response = await fetch(url, { headers: { Accept: 'application/json' } });
      if (!response.ok) throw new Error(`HTTP ${response.status}`);
      return await response.json();
    } catch (err) {
      if (attempt === retries) throw err;
      const delay = backoffMs * 2 ** attempt;
      console.warn(`attempt ${attempt + 1} failed (${err.message}); retrying in ${delay}ms`);
      await new Promise((resolve) => setTimeout(resolve, delay));
    }
  }
}

export default fetchWithRetry;

use std::collections::HashMap;

fn word_counts(text: &str) -> HashMap<&str, usize> {
    let mut counts: HashMap<&str, usize> = HashMap::new();
    for word in text.split_whitespace() {
        *counts.entry(word).or_insert(0) += 1;
    }
    counts
}

fn main() {
    let text = "the quick brown fox jumps over the lazy dog the fox";
    let counts = word_counts(text);
    let mut pairs: Vec<(&str, usize)> = counts.into_iter().collect();
    pairs.sort_by(|a, b| b.1.cmp(&a.1).then(a.0.cmp(b.0)));
    for (word, n) in pairs.iter().take(3) {
        println!("{word}: {n}");
    }
}

class LRUCache:
    """Least-recently-used cache backed by an ordered dict."""

    def __init__(self, capacity: int) -> None:
        if capacity <= 0:
            raise ValueError(f"capacity must be positive, got {capacity}")
        self.capacity = capacity
        self._store: dict[str, object] = {}

    def get(self, key: str, default=None):
        if key not in self._store:
            return default
        self._store[key] = value = self._store.pop(key)
        return value

    def put(self, key: str, value) -> None:
        self._store.pop(key, None)
        self._store[key] = value
        while len(self._store) > self.capacity:
            oldest = next(iter(self._store))
            del self._store[oldest]

import torch
import torch.nn as nn
import torch.nn.functional as F


class MLP(nn.Module):
    def __init__(self, d_model: int, d_hidden: int, dropout: float = 0.1):
        super().__init__()
        self.up_proj = nn.Linear(d_model, d_hidden, bias=False)
        self.gate_proj = nn.Linear(d_model, d_hidden, bias=False)
        self.down_proj = nn.Linear(d_hidden, d_model, bias=False)
        self.dropout = nn.Dropout(dropout)

    def forward(self, x: torch.Tensor) -> torch.Tensor:
        return self.dropout(self.down_proj(F.silu(self.gate_proj(x)) * self.up_proj(x)))

def parse_duration(raw: str) -> int:
    """Parse '2h30m', '45s', '1d' into seconds."""
    units = {"d": 86400, "h": 3600, "m": 60, "s": 1}
    total, digits = 0, ""
    for ch in raw.strip().lower():
        if ch.isdigit():
            digits += ch
        elif ch in units and digits:
            total += int(digits) * units[ch]
            digits = ""
        else:
            raise ValueError(f"bad duration: {raw!r}")
    if digits:
        raise ValueError(f"trailing number without unit in {raw!r}")
    return total


assert parse_duration("2h30m") == 9000
assert parse_duration("1d") == 86400
